<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <title>Personal Expense Tracker</title>
  <style>
    body { font-family: Arial, sans-serif; margin: 20px; }
    .form-group { margin-bottom: 10px; }
    label { display: inline-block; width: 80px; }
    input, select { padding: 5px; }
    button { padding: 5px 10px; cursor: pointer; }
    table { border-collapse: collapse; width: 100%; margin-top: 20px; }
    th, td { border: 1px solid #ddd; padding: 8px; text-align: left; }
    tr:nth-child(even) { background-color: #f2f2f2; }
    .exp-del { background-color: #ff4444; color: white; border: none; }
    .cat-total { margin-top: 10px; font-weight: bold; }
    #form-error { color: red; }
  </style>
</head>
<body>

<h2>Add Expense</h2>
<div id="form-error"></div>
<form id="expense-form">
  <div class="form-group">
    <label for="amount">Amount:</label>
    <input type="number" step="0.01" id="amount" required />
  </div>
  <div class="form-group">
    <label for="category">Category:</label>
    <select id="category">
      <option value="groceries">Groceries</option>
      <option value="transport">Transport</option>
      <option value="bills">Bills</option>
      <option value="fun">Fun</option>
    </select>
  </div>
  <div class="form-group">
    <label for="date">Date:</label>
    <input type="date" id="date" required />
  </div>
  <div class="form-group">
    <label for="note">Note:</label>
    <input type="text" id="note" placeholder="Optional note" />
  </div>
  <button type="submit" id="add-expense">Add Expense</button>
</form>

<h2>Filters</h2>
<div class="form-group">
  <label for="filter-category">Category:</label>
  <select id="filter-category">
    <option value="all">All</option>
    <option value="groceries">Groceries</option>
    <option value="transport">Transport</option>
    <option value="bills">Bills</option>
    <option value="fun">Fun</option>
  </select>
</div>
<div class="form-group">
  <label for="filter-from">From:</label>
  <input type="date" id="filter-from" />
</div>
<div class="form-group">
  <label for="filter-to">To:</label>
  <input type="date" id="filter-to" />
</div>

<h2>Expenses</h2>
<table id="expense-table">
  <thead>
    <tr><th>Amount</th><th>Category</th><th>Date</th><th>Note</th><th></th></tr>
  </thead>
  <tbody id="expense-list"></tbody>
</table>

<div id="total-container">
  Total: <span id="total">0.00</span>
</div>

<div id="category-summary"></div>

<script>
  document.addEventListener('DOMContentLoaded', () => {
    const form = document.getElementById('expense-form');
    const amountInput = document.getElementById('amount');
    const categorySelect = document.getElementById('category');
    const dateInput = document.getElementById('date');
    const noteInput = document.getElementById('note');
    const addBtn = document.getElementById('add-expense');
    const formError = document.getElementById('form-error');
    const expenseList = document.getElementById('expense-list');
    const totalSpan = document.getElementById('total');
    const filterCategory = document.getElementById('filter-category');
    const filterFrom = document.getElementById('filter-from');
    const filterTo = document.getElementById('filter-to');
    const categorySummary = document.getElementById('category-summary');

    let expenses = JSON.parse(localStorage.getItem('expenses')) || [];

    function saveExpenses() {
      localStorage.setItem('expenses', JSON.stringify(expenses));
    }

    function renderExpenses() {
      expenseList.innerHTML = '';
      const filtered = filterExpenses();
      filtered.forEach(expense => {
        const row = document.createElement('tr');
        row.className = 'expense';
        row.innerHTML = `
          <td>${expense.amount.toFixed(2)}</td>
          <td>${expense.category}</td>
          <td>${expense.date}</td>
          <td>${expense.note || ''}</td>
          <td><button class="exp-del">Delete</button></td>
        `;
        row.querySelector('.exp-del').addEventListener('click', () => {
          expenses = expenses.filter(e => e !== expense);
          saveExpenses();
          renderExpenses();
          updateSummary();
        });
        expenseList.appendChild(row);
      });
      updateTotal(filtered);
    }

    function filterExpenses() {
      const catFilter = filterCategory.value;
      const fromDate = filterFrom.value;
      const toDate = filterTo.value;

      return expenses.filter(expense => {
        if (catFilter !== 'all' && expense.category !== catFilter) return false;
        if (fromDate && expense.date < fromDate) return false;
        if (toDate && expense.date > toDate) return false;
        return true;
      });
    }

    function updateTotal(filtered) {
      const sum = filtered.reduce((acc, e) => acc + parseFloat(e.amount), 0);
      totalSpan.textContent = sum.toFixed(2);
    }

    function updateSummary() {
      categorySummary.innerHTML = '';
      const cats = ['groceries', 'transport', 'bills', 'fun'];
      cats.forEach(cat => {
        const filtered = filterExpenses().filter(e => e.category === cat);
        const sum = filtered.reduce((acc, e) => acc + parseFloat(e.amount), 0);
        if (sum > 0) {
          const div = document.createElement('div');
          div.className = 'cat-total';
          div.setAttribute('data-cat', cat);
          div.textContent = `${cat}: ${sum.toFixed(2)}`;
          categorySummary.appendChild(div);
        }
      });
    }

    form.addEventListener('submit', (e) => {
      e.preventDefault();
      const amount = parseFloat(amountInput.value);
      const category = categorySelect.value;
      const date = dateInput.value;
      const note = noteInput.value;

      if (!amount || isNaN(amount) || amount <= 0 || !date) {
        formError.textContent = 'Invalid amount or missing date.';
        return;
      }

      expenses.unshift({ amount, category, date, note });
      saveExpenses();
      formError.textContent = '';
      amountInput.value = '';
      renderExpenses();
      updateSummary();
    });

    filterCategory.addEventListener('change', () => {
      renderExpenses();
      updateSummary();
    });

    filterFrom.addEventListener('change', () => {
      renderExpenses();
      updateSummary();
    });

    filterTo.addEventListener('change', () => {
      renderExpenses();
      updateSummary();
    });

    // Initial render
    renderExpenses();
    updateSummary();
  });
</script>

</body>
</html>
